begin
wwv_flow_api.create_page(
 p_id=>1
,p_user_interface_id=>wwv_flow_api.id(368616654788764442)
,p_name=>'Home'
,p_alias=>'HOME'
,p_step_title=>unistr('GEST\00C3O DOS PRODUTOS COM BENEFICIOS TRIBUTADOS')
,p_autocomplete_on_off=>'OFF'
,p_javascript_code_onload=>wwv_flow_string.join(wwv_flow_t_varchar2(
'// ================================================================',
unistr('// BLOCO 1 \2014 Refresh do Monitor de Execu\00E7\00E3o (INDEPENDENTE)'),
'// ================================================================',
'try {',
'    var INTERVALO_MONITOR = 5000; // 5 segundos',
'',
'    if (window._monitorTimer) { clearInterval(window._monitorTimer); window._monitorTimer = null; }',
'',
'    var ID_MONITOR = ''regiao_monitor_execucao'';',
'',
'    // Spinner',
'    function setupSpinnerMonitor() {',
'        var region = document.getElementById(ID_MONITOR);',
'        if (!region) return;',
'        var header = region.querySelector(''.t-Region-header'');',
'        if (header && !header.querySelector(''.refresh-spinner'')) {',
'            var spinner = document.createElement(''div'');',
'            spinner.className = ''refresh-spinner'';',
'            spinner.innerHTML = ''<div class="spinner-ring"></div>'';',
'            spinner.style.cssText = ''position:absolute;top:14px;right:16px;opacity:0;transition:opacity 0.2s;'';',
'            header.style.position = ''relative'';',
'            header.appendChild(spinner);',
'        }',
'    }',
'',
'    function refreshMonitor() {',
'        try {',
'            var el = document.getElementById(ID_MONITOR);',
'            if (!el) return;',
'',
'            var sp = el.querySelector(''.refresh-spinner'');',
'            if (sp) sp.style.opacity = ''1'';',
'',
'            // Tenta apex.region',
'            try {',
'                var reg = apex.region(ID_MONITOR);',
'                if (reg && typeof reg.refresh === ''function'') {',
'                    reg.refresh();',
unistr('                    console.log(''\2705 Monitor atualizado \2014 '' + new Date().toLocaleTimeString());'),
'                    setTimeout(function() { if (sp) sp.style.opacity = ''0''; }, 1200);',
'                    return;',
'                }',
'            } catch(e) {}',
'',
'            // Fallback: trigger',
'            apex.jQuery(''#'' + ID_MONITOR).trigger(''apexrefresh'');',
unistr('            console.log(''\2705 Monitor atualizado (trigger) \2014 '' + new Date().toLocaleTimeString());'),
'            setTimeout(function() { if (sp) sp.style.opacity = ''0''; }, 1200);',
'',
'        } catch(e) {',
unistr('            console.log(''\274C Monitor erro: '' + e.message);'),
'        }',
'    }',
'',
'    setTimeout(function() {',
'        setupSpinnerMonitor();',
'        refreshMonitor();',
unistr('        console.log(''\D83D\DD04 Monitor: refresh inicial'');'),
'    }, 2000);',
'',
'    window._monitorTimer = setInterval(refreshMonitor, INTERVALO_MONITOR);',
'',
unistr('    console.log(''\2705 Timer MONITOR iniciado \2014 '' + INTERVALO_MONITOR + ''ms'');'),
'',
unistr('} catch(e) { console.log(''\274C ERRO BLOCO 1:'', e); }'),
'',
'',
'// ================================================================',
unistr('// BLOCO 2 \2014 Refresh da CBS + Painel Opera\00E7\00F5es Fiscais (INDEPENDENTE)'),
'// ================================================================',
'try {',
'    var INTERVALO_CBS = 9000; // 9 segundos',
'',
'    if (window._cbsTimer) { clearInterval(window._cbsTimer); window._cbsTimer = null; }',
'',
'    var ID_CBS    = ''PAINEL_CONSOLIDACAO'';',
'    var ID_PAINEL = ''regiao-transacao'';',
'',
'    function refreshCBS() {',
'        // CBS',
'        try {',
'            var el = document.getElementById(ID_CBS) || document.getElementById(ID_CBS + '' '');',
'            if (el) {',
'                var idReal = el.id;',
'                try {',
'                    var reg = apex.region(idReal);',
'                    if (reg && typeof reg.refresh === ''function'') {',
'                        reg.refresh();',
unistr('                        console.log(''\2705 CBS atualizado \2014 '' + new Date().toLocaleTimeString());'),
'                    }',
'                } catch(e) {',
'                    apex.jQuery(''#'' + idReal).trigger(''apexrefresh'');',
unistr('                    console.log(''\2705 CBS atualizado (trigger) \2014 '' + new Date().toLocaleTimeString());'),
'                }',
'            }',
'        } catch(e) {',
unistr('            console.log(''\274C CBS erro: '' + e.message);'),
'        }',
'',
unistr('        // Painel de Opera\00E7\00F5es Fiscais'),
'        try {',
'            var elPainel = document.getElementById(ID_PAINEL);',
'            if (elPainel) {',
'                try {',
'                    var regP = apex.region(ID_PAINEL);',
'                    if (regP && typeof regP.refresh === ''function'') {',
'                        regP.refresh();',
unistr('                        console.log(''\2705 Painel Opera\00E7\00F5es Fiscais atualizado \2014 '' + new Date().toLocaleTimeString());'),
'                    }',
'                } catch(e) {',
'                    apex.jQuery(''#'' + ID_PAINEL).trigger(''apexrefresh'');',
unistr('                    console.log(''\2705 Painel atualizado (trigger) \2014 '' + new Date().toLocaleTimeString());'),
'                }',
'            }',
'        } catch(e) {',
unistr('            console.log(''\274C Painel erro: '' + e.message);'),
'        }',
'    }',
'',
'    setTimeout(function() {',
'        refreshCBS();',
unistr('        console.log(''\D83D\DD04 CBS + Painel: refresh inicial'');'),
'    }, 3000);',
'',
'    window._cbsTimer = setInterval(refreshCBS, INTERVALO_CBS);',
'',
unistr('    console.log(''\2705 Timer CBS + PAINEL iniciado \2014 '' + INTERVALO_CBS + ''ms'');'),
'',
unistr('} catch(e) { console.log(''\274C ERRO BLOCO 2:'', e); }'),
'',
'',
'// ================================================================',
unistr('// BLOCO 3 \2014 FIX COLUNAS (DETEC\00C7\00C3O POR NOME)'),
'// ================================================================',
'try {',
'(function() {',
'    function fixPainel() {',
'        var painel = document.querySelector(''.timeline-nfe'');',
'        if (!painel) return;',
'        var tabela = painel.querySelector(''table'');',
'        if (!tabela) return;',
'',
'        var cg = tabela.querySelector(''colgroup'');',
'        if (cg) cg.parentNode.removeChild(cg);',
'',
'        tabela.style.setProperty(''table-layout'', ''auto'', ''important'');',
'        tabela.style.setProperty(''width'', ''100%'', ''important'');',
'        tabela.style.setProperty(''border-collapse'', ''collapse'', ''important'');',
'',
'        var allThs = tabela.querySelectorAll(''thead th'');',
'        var total = allThs.length;',
'',
'        var keywords = [''DETALHE'', ''CATEGORIA'', ''INDICADOR'', ''FASE''];',
'        var configs  = [',
'            [''left'',   ''38%''],',
'            [''center'', ''14%''],',
'            [''left'',   ''22%''],',
'            [''left'',   ''26%'']',
'        ];',
'',
'        var colMap = {};',
'        for (var i = 0; i < total; i++) {',
'            var txt = allThs[i].textContent.trim().toUpperCase();',
'            var found = false;',
'            for (var k = 0; k < keywords.length; k++) {',
'                if (txt.indexOf(keywords[k]) > -1) {',
'                    colMap[i] = configs[k];',
'                    found = true;',
'                    break;',
'                }',
'            }',
'            if (!found) colMap[i] = null;',
'        }',
'',
'        for (var i = 0; i < total; i++) {',
'            if (colMap[i]) {',
'                allThs[i].style.setProperty(''display'', ''table-cell'', ''important'');',
'                allThs[i].style.setProperty(''text-align'', colMap[i][0], ''important'');',
'                allThs[i].style.setProperty(''width'', colMap[i][1], ''important'');',
'                allThs[i].style.setProperty(''padding'', ''10px 12px'', ''important'');',
'            } else {',
'                allThs[i].style.setProperty(''display'', ''none'', ''important'');',
'                allThs[i].style.setProperty(''padding'', ''0'', ''important'');',
'                allThs[i].style.setProperty(''border'', ''none'', ''important'');',
'                allThs[i].style.setProperty(''overflow'', ''hidden'', ''important'');',
'            }',
'        }',
'',
'        var rows = tabela.querySelectorAll(''tbody tr'');',
'        for (var r = 0; r < rows.length; r++) {',
'            var cells = rows[r].querySelectorAll(''td'');',
'            for (var j = 0; j < cells.length; j++) {',
'                if (colMap[j]) {',
'                    cells[j].style.setProperty(''display'', ''table-cell'', ''important'');',
'                    cells[j].style.setProperty(''text-align'', colMap[j][0], ''important'');',
'                    cells[j].style.setProperty(''width'', colMap[j][1], ''important'');',
'                    cells[j].style.setProperty(''padding'', ''8px 12px'', ''important'');',
'                } else {',
'                    cells[j].style.setProperty(''display'', ''none'', ''important'');',
'                    cells[j].style.setProperty(''padding'', ''0'', ''important'');',
'                    cells[j].style.setProperty(''border'', ''none'', ''important'');',
'                    cells[j].style.setProperty(''overflow'', ''hidden'', ''important'');',
'                }',
'            }',
'        }',
'    }',
'',
'    fixPainel();',
'    setTimeout(fixPainel, 500);',
'    setTimeout(fixPainel, 1500);',
'    setTimeout(fixPainel, 3000);',
'',
'    apex.jQuery(document).on(''apexafterrefresh'', function() {',
'        setTimeout(fixPainel, 300);',
'        setTimeout(fixPainel, 800);',
'    });',
'})();',
unistr('} catch(e) { console.log(''\274C ERRO BLOCO 3:'', e); }'),
'',
'',
'// ================================================================',
unistr('// BLOCO 4 \2014 Badges Visuais (Categoria + Status + Fase)'),
'// ================================================================',
'try {',
'(function() {',
'',
'    var CORES_CATEGORIA = {',
'        ''SISTEMA'':     { bg: ''#E3F2FD'', cor: ''#1565C0'', borda: ''#90CAF9'' },',
unistr('        ''INFORMA\00C7\00C3O'':  { bg: ''#E8F5E9'', cor: ''#2E7D32'', borda: ''#A5D6A7'' },'),
'        ''INFORMACAO'':  { bg: ''#E8F5E9'', cor: ''#2E7D32'', borda: ''#A5D6A7'' },',
'        ''ERRO'':        { bg: ''#FFEBEE'', cor: ''#C62828'', borda: ''#EF9A9A'' },',
'        ''ERROR'':       { bg: ''#FFEBEE'', cor: ''#C62828'', borda: ''#EF9A9A'' },',
'        ''ALERTA'':      { bg: ''#FFF8E1'', cor: ''#F57F17'', borda: ''#FFE082'' },',
'        ''WARNING'':     { bg: ''#FFF8E1'', cor: ''#F57F17'', borda: ''#FFE082'' }',
'    };',
'',
'    var CORES_STATUS = {',
'        ''success'':  { bg: ''#E8F5E9'', cor: ''#2E7D32'', dot: ''#4CAF50'', label: ''Sucesso'' },',
'        ''sucesso'':  { bg: ''#E8F5E9'', cor: ''#2E7D32'', dot: ''#4CAF50'', label: ''Sucesso'' },',
'        ''info'':     { bg: ''#E3F2FD'', cor: ''#1565C0'', dot: ''#2196F3'', label: ''Info'' },',
'        ''error'':    { bg: ''#FFEBEE'', cor: ''#C62828'', dot: ''#F44336'', label: ''Erro'' },',
'        ''erro'':     { bg: ''#FFEBEE'', cor: ''#C62828'', dot: ''#F44336'', label: ''Erro'' },',
'        ''warning'':  { bg: ''#FFF8E1'', cor: ''#F57F17'', dot: ''#FF9800'', label: ''Alerta'' },',
'        ''alerta'':   { bg: ''#FFF8E1'', cor: ''#F57F17'', dot: ''#FF9800'', label: ''Alerta'' },',
'        ''pending'':  { bg: ''#F3E5F5'', cor: ''#7B1FA2'', dot: ''#9C27B0'', label: ''Pendente'' }',
'    };',
'',
'    var EMOJIS_FASE = {',
unistr('        ''leitura'':       { emoji: ''\D83D\DCD6'', cor: ''#1565C0'' },'),
unistr('        ''recep'':         { emoji: ''\D83D\DCE5'', cor: ''#2E7D32'' },'),
unistr('        ''extra'':         { emoji: ''\D83D\DCE6'', cor: ''#F57F17'' },'),
unistr('        ''valida'':        { emoji: ''\2705'', cor: ''#00897B'' },'),
unistr('        ''fiscal'':        { emoji: ''\D83D\DD0D'', cor: ''#5E35B1'' },'),
