unistr('        ''credito'':       { emoji: ''\D83D\DCB3'', cor: ''#1565C0'' },'),
unistr('        ''lote'':          { emoji: ''\D83D\DCE6'', cor: ''#00838F'' },'),
unistr('        ''atualiza'':      { emoji: ''\D83D\DD04'', cor: ''#0277BD'' }'),
'    };',
'',
unistr('    var DEFAULT_FASE = { emoji: ''\D83D\DCCB'', cor: ''#546E7A'' };'),
'    var DEFAULT_CAT  = { bg: ''#F5F5F5'', cor: ''#616161'', borda: ''#E0E0E0'' };',
'    var DEFAULT_STS  = { bg: ''#F5F5F5'', cor: ''#616161'', dot: ''#9E9E9E'', label: '''' };',
'',
'    function encontrarEmojiFase(texto) {',
'        var t = texto.toLowerCase();',
'        var keys = Object.keys(EMOJIS_FASE);',
'        for (var i = 0; i < keys.length; i++) {',
'            if (t.indexOf(keys[i]) > -1) return EMOJIS_FASE[keys[i]];',
'        }',
'        return DEFAULT_FASE;',
'    }',
'',
'    function aplicarBadges() {',
'        var regiao = document.getElementById(''PAINEL_CONSOLIDACAO'') || ',
'                     document.getElementById(''PAINEL_CONSOLIDACAO '');',
'        if (!regiao) return;',
