,p_name=>unistr('Central de Valida\00E7\00E3o de Cr\00E9ditos (CBS)')
,p_region_name=>'PAINEL_CONSOLIDACAO'
,p_parent_plug_id=>wwv_flow_api.id(369373586204795162)
,p_template=>wwv_flow_api.id(368531481571764214)
,p_display_sequence=>30
,p_region_css_classes=>'timeline-nfe'
,p_region_template_options=>'#DEFAULT#:t-Region--scrollBody'
,p_component_template_options=>'#DEFAULT#:t-Report--altRowsDefault:t-Report--rowHighlight'
,p_display_point=>'BODY'
,p_source_type=>'NATIVE_SQL_REPORT'
,p_query_type=>'SQL'
,p_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT *',
'FROM (',
'    SELECT',
'        ROWNUM           AS ID,',
'        DESCRICAO        AS DETALHE_DA_OPERACAO,',
'        CATEGORIA        AS CATEGORIA,',
'        CASE',
'            WHEN UPPER(CATEGORIA) LIKE ''%SISTEMA%''     THEN ''sistema''',
'            WHEN UPPER(CATEGORIA) LIKE ''%INFORMA%''     THEN ''informacao''',
'            WHEN UPPER(CATEGORIA) LIKE ''%ERROR%''        THEN ''error''',
'            WHEN UPPER(CATEGORIA) LIKE ''%ALERTA%''       THEN ''alerta''',
'            ELSE ''default''',
'        END AS CATEGORIA_CSS,',
'        STATUS_COR       AS INDICADOR_DE_STATUS,',
'        CASE',
'            WHEN LOWER(STATUS_COR) = ''success''              THEN ''success''',
'            WHEN LOWER(STATUS_COR) = ''info''                  THEN ''info''',
'            WHEN LOWER(STATUS_COR) IN (''error'',''erro'')       THEN ''error''',
'            WHEN LOWER(STATUS_COR) IN (''warning'',''alerta'')   THEN ''warning''',
'            ELSE ''pending''',
'        END AS STATUS_CSS,',
'        CASE',
'            WHEN LOWER(STATUS_COR) = ''success''              THEN ''Sucesso''',
'            WHEN LOWER(STATUS_COR) = ''info''                  THEN ''Info''',
'            WHEN LOWER(STATUS_COR) IN (''error'',''erro'')       THEN ''Erro''',
'            WHEN LOWER(STATUS_COR) IN (''warning'',''alerta'')   THEN ''Alerta''',
'            ELSE STATUS_COR',
'        END AS STATUS_LABEL,',
'        TITULO           AS FASE_DO_PROCESSAMENTO',
'    FROM VW_DASH_AUDITORIA_RF',
'    WHERE DATA_HORA IS NULL',
')',
'ORDER BY 1'))
,p_ajax_enabled=>'Y'
,p_lazy_loading=>true
,p_query_row_template=>wwv_flow_api.id(368560366059764250)
,p_query_num_rows=>15
,p_query_options=>'DERIVED_REPORT_COLUMNS'
,p_query_num_rows_type=>'NEXT_PREVIOUS_LINKS'
,p_pagination_display_position=>'BOTTOM_RIGHT'
,p_csv_output=>'N'
,p_prn_output=>'N'
,p_sort_null=>'L'
,p_plug_query_strip_html=>'N'
);
