wwv_flow_api.create_page_plug(
 p_id=>wwv_flow_api.id(371575094756349576)
,p_plug_name=>unistr('Monitor de Execu\00E7\00E3o do Processamento')
,p_region_name=>'monitor_execucao'
,p_parent_plug_id=>wwv_flow_api.id(369373586204795162)
,p_region_template_options=>'#DEFAULT#:t-Region--scrollBody'
,p_component_template_options=>'#DEFAULT#'
,p_plug_template=>wwv_flow_api.id(368531481571764214)
,p_plug_display_sequence=>10
,p_plug_display_point=>'BODY'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'declare',
'  cursor c_tasks is',
'    SELECT ELAPSED_TIME id, a.job_name as xml',
'    FROM dba_scheduler_running_jobs a',
'    WHERE owner = ''USER_XMLS'';',
'  v_count number := 0;',
'begin',
'  sys.htp.p(''<ul>'');',
'  for a in c_tasks loop',
'    v_count := v_count + 1;',
'    sys.htp.p(''<li>'' || a.id || '' ('' || a.xml || '')</li>'');',
'  end loop;',
'  sys.htp.p(''</ul>'');',
'',
'  if v_count = 0 then',
'    sys.htp.p(''',
'      <div style="',
'        display:flex;align-items:center;gap:12px;padding:16px 20px;',
'        background:rgba(79,140,255,0.04);',
'        border:2px dashed rgba(79,140,255,0.25);',
'        border-radius:10px;color:#4a4a7b;font-size:13px;',
'      ">',
'        <span style="',
'          width:32px;height:32px;background:rgba(79,140,255,0.08);',
'          border-radius:50%;display:flex;align-items:center;justify-content:center;',
'          font-size:16px;flex-shrink:0;',
'        ">&#9208;</span>',
'        <div>',
'          <strong>Nenhum job em execucao</strong><br/>',
'          <span style="font-size:12px;color:#8888aa;">O scheduler nao possui tarefas ativas no momento</span>',
'        </div>',
'      </div>',
'    '');',
'  end if;',
'end;'))
,p_plug_source_type=>'NATIVE_PLSQL'
,p_plug_query_options=>'DERIVED_REPORT_COLUMNS'
);
