wwv_flow_api.create_page_process(
 p_id=>wwv_flow_api.id(369374332444795170)
,p_process_sequence=>10
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'PROC_VERIFY'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'declare ',
'   ln number;',
'   p_USER_APEX VARCHAR2(128):= ''DEVELOPER'';',
'   lprocid  NUMBER ;',
'   res VARCHAR2(4000):= APEX_APPLICATION.g_user;',
'   vprocid  number;',
'   begin ',
'            ',
'  select SEQ.NEXTVAL',
'   INTO lprocid',
'  from dual  ;        ',
'',
'',
'  select  count(*) ',
'    into ln  ',
'  from  dba_scheduler_running_jobs',
'  where owner = ''APEX'';',
'',
'    vprocid := lprocid;',
'',
'apex_util.set_session_state(''G_PROCID'', lprocid);',
'',
'',
' IF LN > 0  THEN ',
'  Raise_Application_Error (-20343, '' Processo em andamento!.'');',
'  ELSE',
'  ',
'    ---  res := ''leonardo'';',
'                    ',
'                    BEGIN',
'                    DBMS_SCHEDULER.create_job (',
'                    job_name     => res||''_One_Time_Job'',',
'                    job_type     => ''PLSQL_BLOCK'' ,',
'                    job_action   => '' BEGIN',
'                                                     BEGIN',
'                                                     prc_truncate_table;',
'                                                     END;',
'',
'                                                     BEGIN',
'                                                     pack_verify_xml.prc_ins_logproc_xml(''||lprocid||'');',
'                                                     END;     ',
'',
'                                                     BEGIN',
'                                                     pack_verify_xml.prc_verify_allV2('' || lprocid || '','' ||''''''''||res ||''''''''||'');',
'                                                     END;                                                   ',
'                                                     ',
'                                                     BEGIN',
'                                                     pack_cfe.prc_exec_cfe(''||lprocid||'');',
'                                                     END;     ',
'',
'',
'                                                    ',
'                                                     BEGIN  ',
'                                                     pack_nfe.proc_start_xml_nfe(''||lprocid||'');',
'                                                     END;',
'',
'                                                     BEGIN',
'                                                     proc_ins_xml_rel_final_cfe_nfe;',
'                                                     END;',
'',
'                                                     BEGIN',
'                                                     PACK_UP_REL_FINAL.PRC_UP_REL_FINAL;',
'                                                      END;',
'',
'                                                END; '',',
'                    start_date   => SYSDATE,',
'                    enabled      => TRUE,',
'                    auto_drop    => TRUE,',
'                    comments     => ''VERYFY_XMLS_JOB_ALL'');',
'                    END;',
'END IF;',
'EXCEPTION ',
'WHEN OTHERS THEN',
'RAISE ;',
'END ;',
'',
'   '))
,p_process_clob_language=>'PLSQL'
,p_process_error_message=>'error'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_api.id(371575292868349578)
,p_process_success_message=>'Processo agendado com sucesso! '
);
