'            ''<span style="color:#856404;background:#fff3cd;''',
'            || ''padding:10px;border-radius:5px;display:inline-block;">''',
unistr('            || ''\26A0\FE0F '' || v_mensagem'),
'            || ''</span>'';',
'',
'    ELSIF v_status = ''INICIADO'' THEN',
'        -- Exibe mensagem de SUCESSO (verde)',
'        APEX_APPLICATION.G_PRINT_SUCCESS_MESSAGE :=',
'            ''<span style="color:#155724;background:#d4edda;''',
'            || ''padding:10px;border-radius:5px;display:inline-block;">''',
unistr('            || ''\2705 '' || v_mensagem'),
'            || ''</span>'';',
'    END IF;',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
