wwv_flow_api.create_page_process(
 p_id=>wwv_flow_api.id(213393087314867028)
,p_process_sequence=>130
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'PRC_GERAR_RELATORIO_RF'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_job_count NUMBER;',
'    v_job_name  CONSTANT VARCHAR2(30) := ''JOB_GERAR_RELATORIO_RF'';',
'    v_action    VARCHAR2(32767);',
'BEGIN',
'    SELECT COUNT(*)',
'      INTO v_job_count',
'      FROM user_scheduler_jobs',
'     WHERE job_name = v_job_name;',
'',
'    IF v_job_count > 0 THEN',
'        RAISE_APPLICATION_ERROR(-20001, ''O processo de relatorio esta em andamento. Aguarde a conclusao.'');',
'    END IF;',
'',
'    v_action := ''',
'    DECLARE',
'        v_qtd_linhas NUMBER;',
'        v_limite     CONSTANT NUMBER := 500000;',
'    BEGIN',
'        SELECT COUNT(*) INTO v_qtd_linhas FROM TB_UNIFICADA_RF;',
'',
'        IF v_qtd_linhas > v_limite THEN',
'            PRC_NFE_REFORMA_CONSOLIDADA;',
'            PRC_NFE_REFORMA_TRIBUTARIA;',
'            PRC_NFE_UNIFICAR_DADOS;',
'            PRC_NFE_GERAR_CSV;',
'        END IF;',
'',
'        IF v_qtd_linhas <= v_limite THEN',
'            PRC_NFE_REFORMA_CONSOLIDADA;',
'            PRC_NFE_REFORMA_TRIBUTARIA;',
'            PRC_NFE_UNIFICAR_DADOS;            ',
'            PRC_NFE_GERAR_XLSX;',
'        END IF;',
'    END;'';',
'',
'    DBMS_SCHEDULER.CREATE_JOB (',
'        job_name   => v_job_name,',
'        job_type   => ''PLSQL_BLOCK'',',
'        job_action => v_action,',
'        start_date => SYSDATE,',
'        enabled    => TRUE,',
'        auto_drop  => TRUE',
'    );',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_process_error_message=>'#SQLERRM_TEXT#'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_api.id(213392939411867027)
,p_process_success_message=>unistr('apex.message.showPageSuccess("O job iniciou a execu\00E7\00E3o em background");')
);
wwv_flow_api.create_page_process(
 p_id=>wwv_flow_api.id(108153425526949109)
,p_process_sequence=>20
,p_process_point=>'ON_DEMAND'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'REFRESH_PAINEL'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_html   CLOB;',
'    v_badge  VARCHAR2(500);',
'    v_status VARCHAR2(500);',
'    v_fase   VARCHAR2(500);',
'    v_count  NUMBER := 0;',
'BEGIN',
'    v_html := ''<table class="t-Report-report" style="width:100%">'';',
'    v_html := v_html || ''<thead><tr>'';',
unistr('    v_html := v_html || ''<th>DETALHE DA OPERA\00C7\00C3O</th>'';'),
'    v_html := v_html || ''<th>CATEGORIA</th>'';',
'    v_html := v_html || ''<th>INDICADOR DE STATUS</th>'';',
'    v_html := v_html || ''<th>FASE DO PROCESSAMENTO</th>'';',
'    v_html := v_html || ''</tr></thead><tbody>'';',
'',
'    FOR r IN (',
'        SELECT *',
'        FROM (',
'            SELECT ',
'                ROWNUM      AS ID,',
'                DESCRICAO   AS DETALHE_DA_OPERACAO,',
'                CATEGORIA   AS CATEGORIA,',
'                STATUS_COR  AS INDICADOR_DE_STATUS,',
'                TITULO      AS FASE_DO_PROCESSAMENTO',
'            FROM VW_DASH_AUDITORIA_RF',
'            WHERE DATA_HORA IS NULL',
'        )',
'        ORDER BY 1',
'    ) LOOP',
'        v_count := v_count + 1;',
'',
'        -- BADGE CATEGORIA',
'        IF UPPER(r.CATEGORIA) LIKE ''%SISTEMA%'' THEN',
'            v_badge := ''<span class="badge-categoria badge-sistema">'' ',
'                || APEX_ESCAPE.HTML(r.CATEGORIA) || ''</span>'';',
'        ELSIF UPPER(r.CATEGORIA) LIKE ''%INFORMA%'' THEN',
'            v_badge := ''<span class="badge-categoria badge-informacao">'' ',
'                || APEX_ESCAPE.HTML(r.CATEGORIA) || ''</span>'';',
'        ELSIF UPPER(r.CATEGORIA) LIKE ''%ERRO%'' THEN',
'            v_badge := ''<span class="badge-categoria badge-erro">'' ',
'                || APEX_ESCAPE.HTML(r.CATEGORIA) || ''</span>'';',
'        ELSIF UPPER(r.CATEGORIA) LIKE ''%ALERTA%'' THEN',
'            v_badge := ''<span class="badge-categoria badge-alerta">'' ',
'                || APEX_ESCAPE.HTML(r.CATEGORIA) || ''</span>'';',
'        ELSE',
'            v_badge := ''<span class="badge-categoria badge-default">'' ',
'                || APEX_ESCAPE.HTML(r.CATEGORIA) || ''</span>'';',
'        END IF;',
'',
'        -- INDICADOR STATUS',
'        IF LOWER(r.INDICADOR_DE_STATUS) = ''success'' THEN',
'            v_status := ''<span class="status-indicator">''',
'                || ''<span class="status-dot success"></span>''',
'                || ''<span>Sucesso</span></span>'';',
'        ELSIF LOWER(r.INDICADOR_DE_STATUS) = ''info'' THEN',
'            v_status := ''<span class="status-indicator">''',
'                || ''<span class="status-dot info"></span>''',
'                || ''<span>Info</span></span>'';',
'        ELSIF LOWER(r.INDICADOR_DE_STATUS) IN (''error'',''erro'') THEN',
'            v_status := ''<span class="status-indicator">''',
'                || ''<span class="status-dot error"></span>''',
'                || ''<span>Erro</span></span>'';',
'        ELSIF LOWER(r.INDICADOR_DE_STATUS) IN (''warning'',''alerta'') THEN',
'            v_status := ''<span class="status-indicator">''',
'                || ''<span class="status-dot warning"></span>''',
'                || ''<span>Alerta</span></span>'';',
'        ELSE',
'            v_status := ''<span class="status-indicator">''',
'                || ''<span class="status-dot pending"></span>''',
'                || ''<span>'' || APEX_ESCAPE.HTML(r.INDICADOR_DE_STATUS) || ''</span></span>'';',
'        END IF;',
'',
'        -- FASE PROCESSAMENTO com icone',
'        IF UPPER(r.FASE_DO_PROCESSAMENTO) LIKE ''%INICIO%'' THEN',
'            v_fase := ''<span class="fase-processamento">''',
'                || ''<span class="fa fa-play-circle"></span>''',
'                || APEX_ESCAPE.HTML(r.FASE_DO_PROCESSAMENTO) || ''</span>'';',
'        ELSIF UPPER(r.FASE_DO_PROCESSAMENTO) LIKE ''%RECEPCAO%'' OR ',
'              UPPER(r.FASE_DO_PROCESSAMENTO) LIKE ''%RECEP%'' THEN',
'            v_fase := ''<span class="fase-processamento">''',
'                || ''<span class="fa fa-download"></span>''',
'                || APEX_ESCAPE.HTML(r.FASE_DO_PROCESSAMENTO) || ''</span>'';',
'        ELSIF UPPER(r.FASE_DO_PROCESSAMENTO) LIKE ''%EXTRA%'' THEN',
'            v_fase := ''<span class="fase-processamento">''',
'                || ''<span class="fa fa-file-archive-o"></span>''',
'                || APEX_ESCAPE.HTML(r.FASE_DO_PROCESSAMENTO) || ''</span>'';',
'        ELSIF UPPER(r.FASE_DO_PROCESSAMENTO) LIKE ''%VALID%'' THEN',
'            v_fase := ''<span class="fase-processamento">''',
'                || ''<span class="fa fa-check-circle"></span>''',
'                || APEX_ESCAPE.HTML(r.FASE_DO_PROCESSAMENTO) || ''</span>'';',
'        ELSIF UPPER(r.FASE_DO_PROCESSAMENTO) LIKE ''%RESUM%'' OR ',
'              UPPER(r.FASE_DO_PROCESSAMENTO) LIKE ''%FINAL%'' THEN',
'            v_fase := ''<span class="fase-processamento">''',
'                || ''<span class="fa fa-flag-checkered"></span>''',
'                || APEX_ESCAPE.HTML(r.FASE_DO_PROCESSAMENTO) || ''</span>'';',
'        ELSIF UPPER(r.FASE_DO_PROCESSAMENTO) LIKE ''%LEITURA%'' OR',
'              UPPER(r.FASE_DO_PROCESSAMENTO) LIKE ''%XML%'' THEN',
'            v_fase := ''<span class="fase-processamento">''',
'                || ''<span class="fa fa-file-code-o"></span>''',
'                || APEX_ESCAPE.HTML(r.FASE_DO_PROCESSAMENTO) || ''</span>'';',
'        ELSE',
'            v_fase := ''<span class="fase-processamento">''',
'                || ''<span class="fa fa-cog"></span>''',
'                || APEX_ESCAPE.HTML(r.FASE_DO_PROCESSAMENTO) || ''</span>'';',
'        END IF;',
'',
'        v_html := v_html || ''<tr>'';',
'        v_html := v_html || ''<td>'' || APEX_ESCAPE.HTML(r.DETALHE_DA_OPERACAO) || ''</td>'';',
'        v_html := v_html || ''<td>'' || v_badge || ''</td>'';',
'        v_html := v_html || ''<td>'' || v_status || ''</td>'';',
'        v_html := v_html || ''<td>'' || v_fase || ''</td>'';',
'        v_html := v_html || ''</tr>'';',
'    END LOOP;',
'',
'    IF v_count = 0 THEN',
'        v_html := v_html || ''<tr><td colspan="4" style="text-align:center;padding:20px;color:#999;">''',
'            || ''<span class="fa fa-inbox" style="font-size:24px;"></span><br>''',
'            || ''Nenhum registro encontrado</td></tr>'';',
'    END IF;',
'',
'    v_html := v_html || ''</tbody></table>'';',
'    v_html := v_html || ''<div style="text-align:right;padding:8px 16px;font-size:11px;color:#888;">''',
'        || ''1 - '' || v_count || ''</div>'';',
'',
'    HTP.P(v_html);',
'',
'EXCEPTION',
'    WHEN OTHERS THEN',
'        HTP.P(''<div class="painel-processando">''',
'            || ''<span class="fa fa-refresh"></span><br>''',
'            || ''Processamento em andamento... Aguarde.''',
'            || ''</div>'');',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
);
end;
/
begin
wwv_flow_api.create_page_process(
 p_id=>wwv_flow_api.id(108153820685949113)
,p_process_sequence=>30
,p_process_point=>'ON_DEMAND'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'REFRESH_MONITOR'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'declare',
'    cursor c_tasks is',
'        SELECT ',
'            a.elapsed_time as tempo_raw,',
'            a.job_name as xml',
'        FROM dba_scheduler_running_jobs a',
'        WHERE owner = ''USER_XMLS'';',
'    ',
'    v_count      number := 0;',
'    v_elapsed    varchar2(100);',
'    v_job        varchar2(200);',
'    v_mins       number;',
'    v_secs       number;',
'    v_hours      number;',
'    v_days       number;',
'    v_total_secs number;',
'begin',
'    for a in c_tasks loop',
'        v_count := v_count + 1;',
'',
'        v_days  := EXTRACT(DAY    FROM a.tempo_raw);',
'        v_hours := EXTRACT(HOUR   FROM a.tempo_raw);',
'        v_mins  := EXTRACT(MINUTE FROM a.tempo_raw);',
'        v_secs  := ROUND(EXTRACT(SECOND FROM a.tempo_raw));',
'        v_job   := a.xml;',
'        v_total_secs := v_days * 86400 + v_hours * 3600 + v_mins * 60 + v_secs;',
'',
'        v_elapsed := LPAD(v_days, 3, ''0'') || ''d '' ||',
'                     LPAD(v_hours, 2, ''0'') || '':'' ||',
'                     LPAD(v_mins, 2, ''0'') || '':'' ||',
'                     LPAD(v_secs, 2, ''0'');',
'',
'        if v_total_secs < 300 then',
'            sys.htp.p(''<div style="display:flex;align-items:center;gap:14px;padding:16px 22px;background:linear-gradient(115deg,#E8F5E9,#F1F8E9);border-left:4px solid #4CAF50;border-radius:10px;margin:10px 0;box-shadow:0 2px 8px rgba(0,0,0,0.06);">'')'
||';',
'        else',
'            sys.htp.p(''<div style="display:flex;align-items:center;gap:14px;padding:16px 22px;background:linear-gradient(115deg,#FFF3E0,#FFF8E1);border-left:4px solid #FF9800;border-radius:10px;margin:10px 0;box-shadow:0 2px 8px rgba(0,0,0,0.06);">'')'
||';',
'        end if;',
'',
'        sys.htp.p(''<div style="width:42px;height:42px;border-radius:50%;border:4px solid #e0e0e0;border-top-color:transparent;animation:spin 1s linear infinite;flex-shrink:0;"></div>'');',
'        sys.htp.p(''<div style="flex:1;">'');',
'        sys.htp.p(''<div style="font-weight:700;color:#1E7032;font-size:14px;">&#9889; Job em execucao</div>'');',
'        sys.htp.p(''<div style="font-size:13px;color:#33691E;margin-top:4px;font-family:monospace;">&#9201; '' || v_elapsed || ''</div>'');',
'        sys.htp.p(''<div style="font-size:13px;color:#558B2F;margin-top:2px;">&#128230; '' || v_job || ''</div>'');',
'        sys.htp.p(''</div>'');',
'        sys.htp.p(''<div style="font-size:11px;color:#689F38;background:rgba(76,175,80,0.1);padding:4px 10px;border-radius:12px;">Atualizado: '' || TO_CHAR(SYSTIMESTAMP, ''HH24:MI:SS'') || ''</div>'');',
'        sys.htp.p(''</div>'');',
'    end loop;',
'',
'    if v_count = 0 then',
'        sys.htp.p(''<div style="display:flex;align-items:center;gap:12px;padding:16px 28px;background:rgba(79,140,255,0.04);border:2px dashed rgba(79,140,255,0.25);border-radius:10px;color:#4a4a7b;font-size:13px;">'');',
'        sys.htp.p(''<span style="width:32px;height:32px;background:rgba(79,140,255,0.08);border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:16px;flex-shrink:0;">&#9208;</span>'');',
'        sys.htp.p(''<div><strong>Nenhum Job em execucao</strong><br/><span style="font-size:12px;color:#8888aa;">O scheduler nao possui tarefas ativas no momento</span></div>'');',
'        sys.htp.p(''</div>'');',
'    end if;',
'end;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
);
null;
end;
/
