wwv_flow_api.create_page_item(
 p_id=>wwv_flow_api.id(334525368692351223)
,p_name=>'P3_PROCID'
,p_item_sequence=>10
,p_item_plug_id=>wwv_flow_api.id(334523815435351207)
,p_use_cache_before_default=>'NO'
,p_prompt=>'ID Process'
,p_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_message        VARCHAR2 (1000);',
'    v_notification   VARCHAR2 (10000);',
'    lnumber number ;',
'BEGIN',
'     SELECT SEQ.NEXTVAL INTO lnumber FROM DUAL ;',
'',
'    FOR item IN (SELECT lnumber  as notification_msg FROM dual)',
'    LOOP',
'        v_message := item.notification_msg || CHR (10) || CHR (10);',
'        v_notification := v_notification || v_message;',
'    END LOOP;',
'',
'    RETURN v_notification;',
'END;'))
,p_source_type=>'FUNCTION_BODY'
,p_source_language=>'PLSQL'
,p_display_as=>'NATIVE_DISPLAY_ONLY'
,p_field_template=>wwv_flow_api.id(368592878133764293)
,p_item_template_options=>'#DEFAULT#'
,p_attribute_01=>'Y'
,p_attribute_02=>'VALUE'
,p_attribute_04=>'Y'
,p_attribute_05=>'PLAIN'
);
wwv_flow_api.create_page_process(
 p_id=>wwv_flow_api.id(336419861683127217)
,p_process_sequence=>10
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'process_save'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE  ',
'L_DATE DATE := TRUNC(TO_DATE(:P3_DATA_EXEC));',
'L_DAY DATE := TRUNC(SYSDATE);',
'',
'BEGIN',
'IF L_DATE = L_DAY THEN ',
'INSERT INTO TOBE_SCHEDULE_JOB (PK,PROCID,NM_USUARIO,NM_DIRETORIO, DATA_INI_EXECUCAO, LOG_EXECUCAO, SPLIT_FILES, EXTENSAO_FILES)',
'VALUES (NULL,:P3_PROCID,:P3_NOME_USUARIO,:P3_DIRETORIO, to_date(TO_CHAR(SYSDATE,''DD/MM/YYYY HH24:Mi''),''DD/MM/YYYY HH24:Mi''),:P3_LOG, :P3_SPLIT, :P3_EXTENSAO_FILE);',
'ELSE  ',
'INSERT INTO TOBE_SCHEDULE_JOB (PK,PROCID,NM_USUARIO,NM_DIRETORIO, DATA_INI_EXECUCAO, LOG_EXECUCAO, SPLIT_FILES, EXTENSAO_FILES)',
'VALUES (NULL,:P3_PROCID,:P3_NOME_USUARIO,:P3_DIRETORIO, to_date(TO_CHAR(L_DATE,''DD/MM/YYYY HH24:Mi''),''DD/MM/YYYY HH24:Mi''),:P3_LOG, :P3_SPLIT, :P3_EXTENSAO_FILE);',
'END IF;',
'',
'EXCEPTION',
'WHEN OTHERS THEN ',
' RAISE ;',
'END ; '))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
);
end;
